const raw = $input.first().json.data;
const rows = JSON.parse(raw);
if (!Array.isArray(rows)) {
  throw new Error('Time entry load JSON must be an array');
}
const preparedRows = rows.map((row) => ({
  ...row,
  loaded_at: new Date().toISOString(),
}));
const byStatus = preparedRows.reduce((acc, row) => {
  acc[row.match_status] = (acc[row.match_status] ?? 0) + 1;
  return acc;
}, {});
return [
  {
    json: {
      rows: preparedRows,
      summary: {
        rowCount: preparedRows.length,
        byStatus,
        matchedLaborCost: Math.round(preparedRows.filter((row) => row.match_status === 'matched').reduce((sum, row) => sum + Number(row.labor_cost ?? 0), 0) * 100) / 100,
        adminLaborCost: Math.round(preparedRows.filter((row) => row.match_status === 'admin').reduce((sum, row) => sum + Number(row.labor_cost ?? 0), 0) * 100) / 100,
      },
    },
  },
];

const rows = $input.all().map((item) => item.json);
const byStatus = rows.reduce((acc, row) => {
  acc[row.match_status] = (acc[row.match_status] ?? 0) + 1;
  return acc;
}, {});
return [
  {
    json: {
      status: 'ok',
      upsertedTimeEntryCount: rows.length,
      byStatus,
      matchedLaborCost: Math.round(rows.filter((row) => row.match_status === 'matched').reduce((sum, row) => sum + Number(row.labor_cost ?? 0), 0) * 100) / 100,
      adminLaborCost: Math.round(rows.filter((row) => row.match_status === 'admin').reduce((sum, row) => sum + Number(row.labor_cost ?? 0), 0) * 100) / 100,
      unmatchedLaborCost: Math.round(rows.filter((row) => row.match_status === 'unmatched').reduce((sum, row) => sum + Number(row.labor_cost ?? 0), 0) * 100) / 100,
      sample: rows.slice(0, 10),
    },
  },
];
